71	  defaults: ReturnType<typeof useAppSettings>["defaults"],
72	  provider: ProviderKind,
73	) {
74	  switch (provider) {
75	    case "codex":
76	    default:
77	      return defaults.customCodexModels;
78	  }
79	}
