/** Identifier for a built-in color theme. */
export type ThemeId = "t3-dark" | "t3-light" | "t3-midnight";

/**
 * Color values that define a visual theme.
 * All values must be valid CSS color strings (hex, rgb, oklch, etc.).
 */
export interface ThemeColors {
  /** Main application background */
  readonly background: string;
  /** Primary text / foreground color */
  readonly foreground: string;
  /** Accent surface color (hover states, subtle fills) */
  readonly accent: string;
  /** Sidebar / navigation panel background */
  readonly sidebar: string;
  /** Main editor / content area background */
  readonly editor: string;
  /** Integrated terminal background */
  readonly terminal: string;
  /** Status bar background */
  readonly statusBar: string;
  /** Card / elevated surface background */
  readonly card: string;
  /** Border and divider color */
  readonly border: string;
  /** Muted surface background */
  readonly muted: string;
  /** Muted / secondary text color */
  readonly mutedForeground: string;
  /** Brand / primary action color */
  readonly primary: string;
  /** Text rendered on primary-colored surfaces */
  readonly primaryForeground: string;
}

/** A complete visual theme definition. */
export interface ThemeDefinition {
  readonly id: ThemeId;
  readonly name: string;
  /** Whether this theme targets dark or light environments. */
  readonly colorScheme: "light" | "dark";
  readonly colors: ThemeColors;
}

/** All built-in themes shipped with T3 Code. */
export const BUILT_IN_THEMES: ReadonlyArray<ThemeDefinition> = [
  {
    id: "t3-light",
    name: "T3 Light",
    colorScheme: "light",
    colors: {
      background: "#ffffff",
      foreground: "#1c1c28",
      accent: "rgba(139,92,246,0.08)",
      sidebar: "#f5f4fb",
      editor: "#fafafe",
      terminal: "#f0eefa",
      statusBar: "#e8e6f8",
      card: "#f9f8ff",
      border: "rgba(0,0,0,0.08)",
      muted: "rgba(0,0,0,0.04)",
      mutedForeground: "#6b6a7e",
      primary: "oklch(0.488 0.217 264)",
      primaryForeground: "#ffffff",
    },
  },
  {
    id: "t3-dark",
    name: "T3 Dark",
    colorScheme: "dark",
    colors: {
      background: "#0a0a0f",
      foreground: "#f0f0f5",
      accent: "rgba(255,255,255,0.04)",
      sidebar: "#0d0d14",
      editor: "#0f0f18",
      terminal: "#07070d",
      statusBar: "#0d0d14",
      card: "#0e0e16",
      border: "rgba(255,255,255,0.06)",
      muted: "rgba(255,255,255,0.04)",
      mutedForeground: "#71717a",
      primary: "oklch(0.588 0.217 264)",
      primaryForeground: "#ffffff",
    },
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    colorScheme: "dark",
    colors: {
      background: "#0d0f1a",
      foreground: "#dde1f0",
      accent: "rgba(79,142,247,0.10)",
      sidebar: "#0a0c16",
      editor: "#0f1120",
      terminal: "#08091a",
      statusBar: "#0a0c16",
      card: "#111322",
      border: "rgba(100,130,255,0.10)",
      muted: "rgba(100,130,255,0.06)",
      mutedForeground: "#8090b0",
      primary: "#4f8ef7",
      primaryForeground: "#ffffff",
    },
  },
] as const;

/** The default theme applied when no selection has been persisted. */
export const DEFAULT_THEME_ID: ThemeId = "t3-dark";

/**
 * Returns the ThemeDefinition for the given ID.
 * Falls back to the default theme if the ID is not found.
 */
export function getThemeById(id: ThemeId): ThemeDefinition {
  const found = BUILT_IN_THEMES.find((t) => t.id === id);
  if (found !== undefined) return found;
  // Unreachable in practice — ThemeId is a closed union of valid IDs
  return BUILT_IN_THEMES.find((t) => t.id === DEFAULT_THEME_ID)!;
}

