import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useState,
  type ReactNode,
} from "react";
import {
  type ThemeDefinition,
  type ThemeId,
  DEFAULT_THEME_ID,
  getThemeById,
} from "@t3tools/shared/theme";

// ─── Storage ─────────────────────────────────────────────────────────────────

const COLOR_THEME_STORAGE_KEY = "t3code:color-theme";
const LEGACY_THEME_STORAGE_KEY = "t3code:theme";

/** Returns the stored ThemeId, falling back to a legacy-aware default. */
function getStoredThemeId(): ThemeId {
  const raw = localStorage.getItem(COLOR_THEME_STORAGE_KEY);
  if (raw === "t3-dark" || raw === "t3-light" || raw === "t3-midnight") return raw;
  // Migrate from the existing light/dark/system preference so users don't
  // experience a jarring shift on first load after the update.
  const legacy = localStorage.getItem(LEGACY_THEME_STORAGE_KEY);
  if (legacy === "light") return "t3-light";
  return DEFAULT_THEME_ID;
}

// ─── Context ─────────────────────────────────────────────────────────────────

interface ThemeContextValue {
  readonly theme: ThemeDefinition;
  readonly setThemeId: (id: ThemeId) => void;
}

export const ThemeContext = createContext<ThemeContextValue | null>(null);

export function useThemeContext(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (ctx === null) {
    throw new Error("useThemeContext must be called inside a <ThemeProvider>.");
  }
  return ctx;
}

// ─── DOM application ─────────────────────────────────────────────────────────

/**
 * Applies all color CSS custom properties for `theme` to the document root,
 * overriding the stylesheet defaults.  Also syncs the `dark` class and
 * `color-scheme` so that Tailwind dark-variant utilities continue to work.
 *
 * The `data-color-theme` attribute is set so other subsystems (e.g. the
 * existing useTheme hook) can detect that a named theme is in control and
 * avoid conflicting with the `.dark` class.
 */
export function applyColorTheme(
  theme: ThemeDefinition,
  suppressTransitions = false,
): void {
  const root = document.documentElement;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  const { colors, colorScheme } = theme;

  // Theme-specific surface variables — used by components that need to target
  // individual surface areas (sidebar, editor, terminal, status bar).
  root.style.setProperty("--t3-sidebar", colors.sidebar);
  root.style.setProperty("--t3-editor", colors.editor);
  root.style.setProperty("--t3-terminal", colors.terminal);
  root.style.setProperty("--t3-status-bar", colors.statusBar);
  root.style.setProperty("--t3-accent", colors.accent);

  // Override the shared palette variables that Tailwind utilities consume so
  // that all existing `bg-background`, `text-foreground`, etc. classes pick up
  // the theme colors automatically.
  root.style.setProperty("--background", colors.background);
  root.style.setProperty("--foreground", colors.foreground);
  root.style.setProperty("--card", colors.card);
  root.style.setProperty("--card-foreground", colors.foreground);
  root.style.setProperty("--popover", colors.card);
  root.style.setProperty("--popover-foreground", colors.foreground);
  root.style.setProperty("--primary", colors.primary);
  root.style.setProperty("--primary-foreground", colors.primaryForeground);
  root.style.setProperty("--secondary", colors.muted);
  root.style.setProperty("--secondary-foreground", colors.foreground);
  root.style.setProperty("--muted", colors.muted);
  root.style.setProperty("--muted-foreground", colors.mutedForeground);
  root.style.setProperty("--accent", colors.muted);
  root.style.setProperty("--accent-foreground", colors.foreground);
  root.style.setProperty("--border", colors.border);
  root.style.setProperty("--input", colors.border);
  root.style.setProperty("--ring", colors.primary);

  // Sync dark-mode class so Tailwind `dark:` utilities and scrollbar CSS apply.
  root.classList.toggle("dark", colorScheme === "dark");
  root.style.setProperty("color-scheme", colorScheme);

  // Tag so external code (e.g. useTheme) can defer to this system.
  root.setAttribute("data-color-theme", theme.id);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal.
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// Apply the initial theme immediately at module load time to prevent a flash
// of unstyled content before React hydrates.
applyColorTheme(getThemeById(getStoredThemeId()));

// ─── Provider ────────────────────────────────────────────────────────────────

/** Provides the active color theme to the component tree and keeps the DOM in sync. */
export function ThemeProvider({ children }: { readonly children: ReactNode }) {
  const [themeId, setThemeIdState] = useState<ThemeId>(() => getStoredThemeId());
  const theme = getThemeById(themeId);

  // Re-apply CSS vars whenever the selected theme changes.
  useEffect(() => {
    applyColorTheme(theme, true);
  }, [theme]);

  const setThemeId = useCallback((id: ThemeId) => {
    localStorage.setItem(COLOR_THEME_STORAGE_KEY, id);
    setThemeIdState(id);
  }, []);

  return <ThemeContext.Provider value={{ theme, setThemeId }}>{children}</ThemeContext.Provider>;
}

