import { BUILT_IN_THEMES, type ThemeColors } from "@t3tools/shared/theme";
import { useColorTheme } from "../hooks/useColorTheme";

// ─── Mini preview ─────────────────────────────────────────────────────────────

/**
 * Renders a scaled-down mock of the editor layout using the provided theme
 * colors so users can preview the palette before selecting it.
 */
function ThemePreview({ colors }: { readonly colors: ThemeColors }) {
  // Sidebar icon-row dots (first is "active")
  const sidebarDots = [
    { opacity: 0.9 },
    { opacity: 0.35 },
    { opacity: 0.35 },
  ] as const;

  // Simulated editor content lines
  const editorLines = [
    { width: 48, opacity: 0.22 },
    { width: 36, opacity: 0.17 },
    { width: 44, opacity: 0.14 },
    { width: 28, opacity: 0.11 },
  ] as const;

  // Colour swatches shown below the preview
  const swatches = [
    { color: colors.background, label: "background" },
    { color: colors.sidebar, label: "sidebar" },
    { color: colors.primary, label: "primary" },
    { color: colors.foreground, label: "foreground" },
  ] as const;

  return (
    <div className="flex flex-col gap-2">
      {/* ── Mini layout ── */}
      <div
        aria-hidden="true"
        className="relative h-16 w-28 overflow-hidden rounded-lg"
        style={{ background: colors.background }}
      >
        {/* Sidebar strip */}
        <div
          className="absolute inset-y-0 left-0 w-8"
          style={{ background: colors.sidebar }}
        />

        {/* Editor area */}
        <div
          className="absolute bottom-3 left-8 right-0 top-0"
          style={{ background: colors.editor }}
        />

        {/* Status bar strip */}
        <div
          className="absolute bottom-0 left-8 right-0 h-3"
          style={{ background: colors.statusBar }}
        />

        {/* Sidebar icon dots */}
        <div className="absolute left-1.5 top-2 flex flex-col gap-1.5">
          {sidebarDots.map((dot, i) => (
            <div
              key={i}
              className="h-1.5 w-4 rounded-full"
              style={{ background: colors.primary, opacity: dot.opacity }}
            />
          ))}
        </div>

        {/* Editor content lines */}
        <div className="absolute left-10 top-2 flex flex-col gap-1.5">
          {editorLines.map((line, i) => (
            <div
              key={i}
              className="h-1 rounded-sm"
              style={{
                background: colors.foreground,
                opacity: line.opacity,
                width: line.width,
              }}
            />
          ))}
        </div>

        {/* Terminal strip (partial, bottom of editor) */}
        <div
          className="absolute bottom-3 left-8 right-0 h-4 border-t"
          style={{
            background: colors.terminal,
            borderColor: colors.border,
          }}
        />

        {/* Accent dot in status bar */}
        <div
          className="absolute bottom-0.5 left-10 h-2 w-2 rounded-full"
          style={{ background: colors.primary }}
        />
      </div>

      {/* ── Colour swatches ── */}
      <div className="flex items-center gap-1.5 px-0.5">
        {swatches.map(({ color, label }) => (
          <div
            key={label}
            title={label}
            className="h-3 w-3 rounded-full border border-black/10 dark:border-white/10"
            style={{ background: color }}
          />
        ))}
      </div>
    </div>
  );
}

// ─── Selector ────────────────────────────────────────────────────────────────

/**
 * Displays all built-in color themes as selectable cards with a visual
 * preview swatch so users can see the palette before committing to it.
 */
export function ThemeSelector() {
  const { theme: activeTheme, setThemeId } = useColorTheme();

  return (
    <div
      className="flex flex-wrap gap-3"
      role="radiogroup"
      aria-label="Color theme"
    >
